import java.io.IOException;
import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;
import org.owasp.html.PolicyFactory;
import org.owasp.html.Sanitizers;

public class UserInputHandler {

    private final PolicyFactory htmlPolicy = Sanitizers.FORMATTING.and(Sanitizers.LINKS);

    public void handleUserInput(HttpServletRequest request, HttpServletResponse response) throws IOException {
        String userInput = request.getParameter("input");

        String sanitizedInput = htmlPolicy.sanitize(userInput);

        String htmlResponse = "<html><body>User input: " + sanitizedInput + "</body></html>";

        response.setContentType("text/html");
        response.getWriter().write(htmlResponse);
    }

}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
